CREATE OR REPLACE FUNCTION f_inv_get_intrate ( as_billno text , adtm_date timestamp(0) ) RETURNS bigint AS $body$
DECLARE

  ldc_int_rate  bigint;
  ldtm_date timestamp(0);

BEGIN
    begin							
      select 	interest_rate
      into STRICT 		ldc_int_rate
      from 		sc_inv_bill_interest_rate_use
      Where  	bill_no = as_billno  
      and   	effective_date =(   SELECT max( effective_date ) 
                                    from 		sc_inv_bill_interest_rate_use 
                                    where 		effective_date  <= adtm_date
                                    and   		bill_no =  as_billno  );
	exception when others then return 0;
    end;

    return ldc_int_rate;

exception when others then return 0;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
